#!/usr/bin/env bash
#
# Lightweight smoke checks for the eqsat toolchain.
# Intended for the Docker artifact layout (PROJECT_ROOT=/opt) or a local checkout.
#
# This file was generated by Cursor AI on 2026-05-10.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"

resolve_project_root() {
	local here="$SCRIPT_DIR"
	if [[ -f "${here}/../../compiler/c2po.py" ]]; then
		(cd "${here}/../.." && pwd)
		return
	fi
	if [[ -f "${here}/../../../compiler/c2po.py" ]]; then
		(cd "${here}/../../.." && pwd)
		return
	fi
	echo "smoke_test: could not locate compiler/c2po.py relative to ${SCRIPT_DIR}" >&2
	return 1
}

PROJECT_ROOT="$(resolve_project_root)" || exit 1
export PYTHONPATH="${PROJECT_ROOT}/compiler${PYTHONPATH:+:${PYTHONPATH}}"

# Container installs use PROJECT_ROOT=/opt; local clones use repo root.
STRICT_ARTIFACT_TOOLCHAIN=false
[[ "$PROJECT_ROOT" == "/opt" ]] && STRICT_ARTIFACT_TOOLCHAIN=true

banner() {
	printf '\n━━ %s ━━\n' "$1"
}

die() {
	echo "smoke_test: error: $*" >&2
	exit 1
}

check_cmd_ok() {
	local name="$1"
	shift
	if ! "$@"; then
		die "${name} check failed: $*"
	fi
}

# cvc5 prints a long banner; keep smoke output readable.
cvc5_version_one_line() {
	cvc5 --version 2>&1 | head -1
}

banner "project layout"
[[ -f "${PROJECT_ROOT}/compiler/c2po.py" ]] || die "missing ${PROJECT_ROOT}/compiler/c2po.py"
printf 'PROJECT_ROOT=%s\n' "${PROJECT_ROOT}"

banner "Python / C2PO"
command -v python3 &>/dev/null || die "python3 not on PATH"
python3 --version
check_cmd_ok 'c2po --version' python3 "${PROJECT_ROOT}/compiler/c2po.py" --version

banner "benchmarks corpus"
benchmarks_txt="${PROJECT_ROOT}/benchmarks/benchmarks.txt"
if [[ -f "${benchmarks_txt}" ]]; then
	line_count="$(wc -l < "${benchmarks_txt}" | tr -d ' ')"
	printf 'benchmark list: %s (%s lines)\n' "${benchmarks_txt}" "${line_count}"
else
	printf 'skip: %s not found (expected in Docker image after build steps)\n' "${benchmarks_txt}"
fi

banner "benchmark run (benchmarks/mavlink/mltl)"
BENCHMARK_SH="${SCRIPT_DIR}/benchmark.sh"
[[ -f "${BENCHMARK_SH}" ]] || die "missing ${BENCHMARK_SH}"
command -v parallel &>/dev/null || die 'GNU parallel is required for benchmark.sh (install package parallel)'
MLTL_DIR="${PROJECT_ROOT}/benchmarks/mavlink/mltl"
[[ -d "${MLTL_DIR}" ]] || die "missing mavlink mltl directory ${MLTL_DIR}"
mavlink_mltl=()
while IFS= read -r __mltl_rel; do
	[[ -z "${__mltl_rel}" ]] && continue
	mavlink_mltl+=( "$(realpath "${__mltl_rel}")" )
done < <(find "${MLTL_DIR}" -maxdepth 1 -type f -iname '*.mltl' | LC_ALL=C sort)
if [[ "${#mavlink_mltl[@]}" -eq 0 ]]; then
	die "no *.mltl files under ${MLTL_DIR}"
fi
smoke_bm_list="$(mktemp)"
smoke_results_dir="${SCRIPT_DIR}/../results"
mkdir -p "${smoke_results_dir}"
cleanup_smoke_bm() {
	rm -f "${smoke_bm_list}"
}
trap cleanup_smoke_bm EXIT

{
	for f in "${mavlink_mltl[@]}"; do printf '%s\n' "${f}"; done
} >"${smoke_bm_list}"

# Ensure benchmark.sh uses the same python3 for greedy runs and (when present) gurobipy for ILP.
if [[ -x /opt/venv/bin/python ]]; then
	export PATH="/opt/venv/bin:${PATH}"
elif [[ -n "${VIRTUAL_ENV:-}" && -x "${VIRTUAL_ENV}/bin/python" ]]; then
	export PATH="${VIRTUAL_ENV}/bin:${PATH}"
elif [[ -x "${PROJECT_ROOT}/.venv/bin/python" ]]; then
	export PATH="${PROJECT_ROOT}/.venv/bin:${PATH}"
fi

# Import alone is insufficient: a missing/invalid license fails at gp.Env().start().
HAVE_GUROBIPY=false
if python3 - <<'GUROBI_SMOKE_PROBE' &>/dev/null
import gurobipy as gp

with gp.Env(empty=True) as env:
    env.start()
GUROBI_SMOKE_PROBE
then
	HAVE_GUROBIPY=true
fi
if [[ "${HAVE_GUROBIPY}" != true ]]; then
	printf 'smoke_test: Gurobi not usable (gurobipy import or gp.Env.start failed); ILP benchmark modes will be skipped.\n'
fi

validate_smoke_bm_json_py='import json, sys
path = sys.argv[1]
with open(path, encoding="utf-8") as fh:
    data = json.load(fh)
if not isinstance(data, dict) or "results" not in data:
    raise SystemExit("benchmark output missing top-level results key")
if not isinstance(data["results"], list):
    raise SystemExit("benchmark output results is not a list")
'

run_smoke_mode() {
	local mode_name="$1"
	local extraction_method="$2"
	local assoc_comm_flag="$3"
	local out_json="${smoke_results_dir}/smoke_test_${mode_name}.json"

	bash "${BENCHMARK_SH}" \
		--quiet \
		--input-file-list "${smoke_bm_list}" \
		--output-json "${out_json}" \
		--timeout 5 \
		--memout 8192 \
		--num-gurobi-threads 1 \
		--num-jobs 1 \
		--extraction-method "${extraction_method}" \
		--multi-arity \
		"${assoc_comm_flag}"

	if ! python3 -c "${validate_smoke_bm_json_py}" "${out_json}"; then
		die "benchmark output is not valid JSON or has unexpected shape (see ${out_json})"
	fi
	printf 'benchmark smoke JSON OK: %s (%d mavlink .mltl files)\n' "${out_json}" "${#mavlink_mltl[@]}"
}

run_smoke_mode "greedy_no_ac" "greedy" "--no-assoc-comm"
run_smoke_mode "greedy_ac" "greedy" "--assoc-comm"
if [[ "${HAVE_GUROBIPY}" == true ]]; then
	run_smoke_mode "ilp_no_ac" "ilp" "--no-assoc-comm"
	run_smoke_mode "ilp_ac" "ilp" "--assoc-comm"
else
	printf 'skip: ILP benchmark modes (ilp_no_ac, ilp_ac); Gurobi probe failed\n'
fi

trap - EXIT
cleanup_smoke_bm


if [[ "${STRICT_ARTIFACT_TOOLCHAIN}" == true ]]; then
	banner "SMT solvers (artifact)"
	check_cmd_ok 'z3' z3 --version
	check_cmd_ok 'cvc5' bash -c 'cvc5 --version >/dev/null'
	printf 'cvc5: %s\n' "$(cvc5_version_one_line)"

	banner "egglog (artifact)"
	command -v egglog &>/dev/null || die "egglog not on PATH"
	command -v egglog-experimental &>/dev/null || die "egglog-experimental not on PATH"
	check_cmd_ok 'egglog' egglog --version
	check_cmd_ok 'egglog-experimental' egglog-experimental --version

	banner "Gurobi Python binding (artifact)"
	venv_py="/opt/venv/bin/python"
	[[ -x "${venv_py}" ]] || die "missing ${venv_py}"
	check_cmd_ok 'import gurobipy' "${venv_py}" -c "import gurobipy"
else
	banner "SMT solvers (optional; install or use Docker for full toolchain)"
	if command -v z3 &>/dev/null; then
		check_cmd_ok 'z3' z3 --version
	else
		printf 'skip (-- not on PATH): z3\n'
	fi
	if command -v cvc5 &>/dev/null; then
		check_cmd_ok 'cvc5' bash -c 'cvc5 --version >/dev/null'
		printf 'cvc5: %s\n' "$(cvc5_version_one_line)"
	else
		printf 'skip (-- not on PATH): cvc5\n'
	fi

	banner "egglog (optional)"
	if command -v egglog &>/dev/null && command -v egglog-experimental &>/dev/null; then
		check_cmd_ok 'egglog' egglog --version
		check_cmd_ok 'egglog-experimental' egglog-experimental --version
	else
		printf 'skip (-- egglog binaries not on PATH)\n'
	fi

	banner "gurobipy (optional)"
	gurobi_python=(python3)
	if [[ -x /opt/venv/bin/python ]]; then
		gurobi_python=(/opt/venv/bin/python)
	elif [[ -n "${VIRTUAL_ENV:-}" && -x "${VIRTUAL_ENV}/bin/python" ]]; then
		gurobi_python=("${VIRTUAL_ENV}/bin/python")
	fi
	if "${gurobi_python[0]}" -c "import gurobipy" 2>/dev/null; then
		printf 'gurobipy import OK (%s)\n' "${gurobi_python[0]}"
	else
		printf 'skip: gurobipy not importable (%s)\n' "${gurobi_python[0]}"
	fi
fi

banner "done"
echo "smoke_test: OK"
